import os
import shutil
import subprocess

def compress_dir(src, dest, format):
    if format == "tar.gz":
        command = ("tar czf {} {}").format(dest, src)
    elif format == "tar.bz2":
        command = ("tar cbjf {} {}").format(dest, src)
    elif format == "zip":
        command = ("zip -r {} {}").format(dest, os.path.basename(src))
    elif format == "7z":
        command = ("7z a {} -t7z {}").format(dest, os.path.basename(src))
    else:
        print("Invalid compression format.")
        return

    try:
        subprocess.check_call(command, shell=True)
    except subprocess.CalledProcessError as e:
        print("Failed to create archive: {}".format(e))

# Example usage:
src = "/path/to/user/directory"
dest = "/path/to/compressed/archive.{}.tar".format(format)
